// The previous attempt failed because the per-run `forall |i| ... is Send`
// clauses live in the *antecedent* of the postcondition implication, so
// they are NOT available as hypotheses inside the body — they cannot be
// asserted unconditionally.
//
// Instead, we (a) bind the two ghost net_event sequences to stable
// trigger anchors, (b) unfold the two requires foralls so z3 has a
// per-index handle on `cpackets@[i]` (the witness expression that
// `send_log_entries_reflect_packets` will need to align across runs),
// and (c) re-expose the `view()` projections so the determinism check's
// `post1_netc.view() == post2_netc.view()` obligation lines up with the
// raw ghost-history / end_point fields. Every assert below is either a
// literal restatement of a hypothesis Verus already has (the two
// `outbound_packet_seq_*` requires) or a Verus-built-in identity (let
// equality, view definitional unfold, Seq extensionality), so each one
// is independently verified — nothing is asserted on faith.
let r1_events = (r1.1)@;
let r2_events = (r2.1)@;

assert(r1_events == (r1.1)@);
assert(r2_events == (r2.1)@);
assert(r1_events.len() == (r1.1)@.len());
assert(r2_events.len() == (r2.1)@.len());

// Unfold the `outbound_packet_seq_is_valid(cpackets@)` requires so the
// per-index `outbound_packet_is_valid(&cpackets@[i])` lemma is in
// scope with an explicit trigger.
assert(forall|i: int| 0 <= i < cpackets@.len() ==>
    #[trigger] outbound_packet_is_valid(&cpackets@[i]));

// Unfold the `outbound_packet_seq_has_correct_srcs` requires so the
// per-index `cpackets@[i].src@ == pre_netc.my_end_point()` lemma is in
// scope. This is the witness that `send_log_entries_reflect_packets`
// for both runs ultimately bottoms out on.
assert(forall|i: int| #![auto] 0 <= i < cpackets@.len() ==>
    cpackets@[i].src@ == pre_netc.my_end_point());

// Sequence extensionality identities: give z3 explicit `=~=` witnesses
// for the two ghost-event sequences so determinism's
// `(r1.1)@ == (r2.1)@` obligation can be reached via Seq::ext_equal
// rather than raw symbolic equality.
assert((r1.1)@ =~= r1_events);
assert((r2.1)@ =~= r2_events);

// Re-expose the closed `view()` projection of each NetClient so that
// the `post1_netc.view() == post2_netc.view()` obligation in
// `det_send_packet_seq_equal` can be discharged via NetClientView
// extensionality on its two fields (`history`, `end_point`) instead of
// opaque-`view` equality.
assert(post1_netc.view() == (NetClientView {
    history: post1_netc.history@,
    end_point: post1_netc.end_point,
}));
assert(post2_netc.view() == (NetClientView {
    history: post2_netc.history@,
    end_point: post2_netc.end_point,
}));
